import{_ as s,o as i,c as a,a2 as t}from"./chunks/framework.CGYl2SZ_.js";const n=JSON.parse('{"title":"mattermost","description":"mattermost 页面","frontmatter":{"title":"mattermost","description":"mattermost 页面"},"headers":[],"relativePath":"channels/mattermost.md","filePath":"channels/mattermost.md"}');const l=s({name:"channels/mattermost.md"},[["render",function(s,n,l,e,h,p){return i(),a("div",null,[...n[0]||(n[0]=[t('<h1 id="mattermost" tabindex="-1">Mattermost <a class="header-anchor" href="#mattermost" aria-label="Permalink to &quot;Mattermost&quot;">​</a></h1><h1 id="mattermost-插件" tabindex="-1">Mattermost（插件） <a class="header-anchor" href="#mattermost-插件" aria-label="Permalink to &quot;Mattermost（插件）&quot;">​</a></h1><p>状态：通过插件支持（机器人令牌 + WebSocket 事件）。支持频道、群组和私信。Mattermost 是一个可自托管的团队消息平台；详细信息和下载请访问官方站点 <a href="https://mattermost.com" target="_blank" rel="noreferrer">mattermost.com</a>。</p><h2 id="需要插件" tabindex="-1">需要插件 <a class="header-anchor" href="#需要插件" aria-label="Permalink to &quot;需要插件&quot;">​</a></h2><p>Mattermost 作为插件发货，未与核心安装捆绑。</p><p>通过 CLI 安装（npm 注册表）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @openclaw/mattermost</span></span></code></pre></div><p>本地检出（从 git 仓库运行时）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./extensions/mattermost</span></span></code></pre></div><p>如果您在设置中选择 Mattermost 并且检测到 git 检出，OpenClaw 会自动提供本地安装路径。</p><p>详情：<a href="/tools/plugin.html">插件</a></p><h2 id="快速设置" tabindex="-1">快速设置 <a class="header-anchor" href="#快速设置" aria-label="Permalink to &quot;快速设置&quot;">​</a></h2><ol><li>安装 Mattermost 插件。</li><li>创建 Mattermost 机器人账户并复制 <strong>机器人令牌</strong>。</li><li>复制 Mattermost <strong>基础 URL</strong>（例如 <code>https://chat.example.com</code>）。</li><li>配置 OpenClaw 并启动网关。</li></ol><p>最小配置：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    mattermost</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      botToken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mm-token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      baseUrl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://chat.example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      dmPolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pairing&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="原生命令" tabindex="-1">原生命令 <a class="header-anchor" href="#原生命令" aria-label="Permalink to &quot;原生命令&quot;">​</a></h2><p>原生命令是可选的。启用后，OpenClaw 通过 Mattermost API 注册 <code>oc_*</code> 斜杠命令，并在网关 HTTP 服务器上接收回调 POST。</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    mattermost</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      commands</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        native</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        nativeSkills</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        callbackPath</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/api/channels/mattermost/command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        // 当 Mattermost 无法直接到达网关时使用（反向代理/公共 URL）</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        callbackUrl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://gateway.example.com/api/channels/mattermost/command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>注意：</p><ul><li><code>native: &quot;auto&quot;</code> 默认为 Mattermost 禁用。设置 <code>native: true</code> 启用。</li><li>如果省略 <code>callbackUrl</code>，OpenClaw 从网关主机/端口 + <code>callbackPath</code> 派生一个。</li><li>对于多账户设置，<code>commands</code> 可以设置在顶层或 <code>channels.mattermost.accounts.&lt;id&gt;.commands</code>（账户值覆盖顶层字段）。</li><li>命令回调使用每命令令牌验证，令牌检查失败时关闭。</li><li>可达性要求：回调端点必须可从 Mattermost 服务器到达。 <ul><li>除非 Mattermost 与 OpenClaw 运行在同一主机/网络命名空间，否则不要将 <code>callbackUrl</code> 设置为 <code>localhost</code>。</li><li>除非该 URL 将 <code>/api/channels/mattermost/command</code> 反向代理到 OpenClaw，否则不要将 <code>callbackUrl</code> 设置为您的 Mattermost 基础 URL。</li><li>快速检查是 <code>curl https://&lt;gateway-host&gt;/api/channels/mattermost/command</code>；GET 应从 OpenClaw 返回 <code>405 Method Not Allowed</code>，而不是 <code>404</code>。</li></ul></li><li>Mattermost 出口白名单要求： <ul><li>如果您的回调目标是私有/tailnet/内部地址，请设置 Mattermost <code>ServiceSettings.AllowedUntrustedInternalConnections</code> 以包含回调主机/域名。</li><li>使用主机/域名条目，而不是完整 URL。 <ul><li>好：<code>gateway.tailnet-name.ts.net</code></li><li>坏：<code>https://gateway.tailnet-name.ts.net</code></li></ul></li></ul></li></ul><h2 id="环境变量-默认账户" tabindex="-1">环境变量（默认账户） <a class="header-anchor" href="#环境变量-默认账户" aria-label="Permalink to &quot;环境变量（默认账户）&quot;">​</a></h2><p>如果在网关主机上更喜欢环境变量，请设置：</p><ul><li><code>MATTERMOST_BOT_TOKEN=...</code></li><li><code>MATTERMOST_URL=https://chat.example.com</code></li></ul><p>环境变量仅适用于 <strong>默认</strong>账户（<code>default</code>）。其他账户必须使用配置值。</p><h2 id="聊天模式" tabindex="-1">聊天模式 <a class="header-anchor" href="#聊天模式" aria-label="Permalink to &quot;聊天模式&quot;">​</a></h2><p>Mattermost 自动回复私信。频道行为由 <code>chatmode</code> 控制：</p><ul><li><code>oncall</code>（默认）：仅在频道中被 @提及 时回复。</li><li><code>onmessage</code>：回复每条频道消息。</li><li><code>onchar</code>：当消息以触发前缀开头时回复。</li></ul><p>配置示例：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    mattermost</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      chatmode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;onchar&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      oncharPrefixes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;!&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>注意：</p><ul><li><code>onchar</code> 仍然响应显式 @提及。</li><li><code>channels.mattermost.legacy</code> 配置支持 <code>chatmode</code>。</li></ul><h2 id="线程和会话" tabindex="-1">线程和会话 <a class="header-anchor" href="#线程和会话" aria-label="Permalink to &quot;线程和会话&quot;">​</a></h2><p>使用 <code>channels.mattermost.replyToMode</code> 控制频道和群组回复是在主频道中还是在线程中回复触发帖子。</p><ul><li><code>off</code>（默认）：仅当入站帖子已在线程中时才在线程中回复。</li><li><code>first</code>：对于顶级频道/群组帖子，在该帖子下启动线程并将对话路由到线程作用域会话。</li><li><code>all</code>：与 Mattermost 今天的 <code>first</code> 行为相同。</li><li>私信忽略此设置，保持非线程化。</li></ul><p>配置示例：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    mattermost</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      replyToMode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;all&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>注意：</p><ul><li>线程作用域会话使用触发帖子 id 作为线程根。</li><li><code>first</code> 和 <code>all</code> 当前相同，因为一旦 Mattermost 有线程根，后续块和媒体继续在同一线程中。</li></ul><h2 id="访问控制-私信" tabindex="-1">访问控制（私信） <a class="header-anchor" href="#访问控制-私信" aria-label="Permalink to &quot;访问控制（私信）&quot;">​</a></h2><ul><li>默认：<code>channels.mattermost.dmPolicy = &quot;pairing&quot;</code>（未知发送者收到配对代码）。</li><li>批准方式： <ul><li><code>openclaw pairing list mattermost</code></li><li><code>openclaw pairing approve mattermost &lt;CODE&gt;</code></li></ul></li><li>公开私信：<code>channels.mattermost.dmPolicy=&quot;open&quot;</code> 加上 <code>channels.mattermost.allowFrom=[&quot;*&quot;]</code>。</li></ul><h2 id="频道-群组" tabindex="-1">频道（群组） <a class="header-anchor" href="#频道-群组" aria-label="Permalink to &quot;频道（群组）&quot;">​</a></h2><ul><li>默认：<code>channels.mattermost.groupPolicy = &quot;allowlist&quot;</code>（提及门控）。</li><li>使用 <code>channels.mattermost.groupAllowFrom</code> 白名单发送者（推荐用户 ID）。</li><li><code>@username</code> 匹配是可变的，仅在 <code>channels.mattermost.dangerouslyAllowNameMatching: true</code> 时启用。</li><li>开放频道：<code>channels.mattermost.groupPolicy=&quot;open&quot;</code>（提及门控）。</li><li>运行时注意：如果完全缺少 <code>channels.mattermost</code>，运行时回退到 <code>groupPolicy=&quot;allowlist&quot;</code> 进行群组检查（即使设置了 <code>channels.defaults.groupPolicy</code>）。</li></ul><h2 id="出站投递目标" tabindex="-1">出站投递目标 <a class="header-anchor" href="#出站投递目标" aria-label="Permalink to &quot;出站投递目标&quot;">​</a></h2><p>将这些目标格式用于 <code>openclaw message send</code> 或 cron/webhook：</p><ul><li><code>channel:&lt;id&gt;</code> 用于频道</li><li><code>user:&lt;id&gt;</code> 用于私信</li><li><code>@username</code> 用于私信（通过 Mattermost API 解析）</li></ul><p>裸不透明 ID（如 <code>64ifufp...</code>）在 Mattermost 中是<strong>模糊的</strong>（用户 ID vs 频道 ID）。</p><p>OpenClaw <strong>首先解析用户</strong>：</p><ul><li>如果 ID 作为用户存在（<code>GET /api/v4/users/&lt;id&gt;</code> 成功），OpenClaw 通过 <code>/api/v4/channels/direct</code> 解析直接频道并发送<strong>私信</strong>。</li><li>否则，ID 被视为<strong>频道 ID</strong>。</li></ul><p>如果您需要确定性行为，请始终使用明确的前缀（<code>user:&lt;id&gt;</code> / <code>channel:&lt;id&gt;</code>）。</p><h2 id="私信频道重试" tabindex="-1">私信频道重试 <a class="header-anchor" href="#私信频道重试" aria-label="Permalink to &quot;私信频道重试&quot;">​</a></h2><p>当 OpenClaw 发送 Mattermost 私信目标并需要先解析直接频道时，它默认重试瞬态直接频道创建失败。</p><p>使用 <code>channels.mattermost.dmChannelRetry</code> 全局调整 Mattermost 插件的行为，或使用 <code>channels.mattermost.accounts.&lt;id&gt;.dmChannelRetry</code> 调整一个账户。</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    mattermost</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      dmChannelRetry</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        maxRetries</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        initialDelayMs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        maxDelayMs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        timeoutMs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>注意：</p><ul><li>这仅适用于私信频道创建（<code>/api/v4/channels/direct</code>），而不是每个 Mattermost API 调用。</li><li>重试适用于瞬态失败，如速率限制、5xx 响应和网络或超时错误。</li><li>4xx 客户端错误（除 <code>429</code> 外）被视为永久性的，不会重试。</li></ul><h2 id="反应-消息工具" tabindex="-1">反应（消息工具） <a class="header-anchor" href="#反应-消息工具" aria-label="Permalink to &quot;反应（消息工具）&quot;">​</a></h2><ul><li>使用 <code>message action=react</code> 与 <code>channel=mattermost</code>。</li><li><code>messageId</code> 是 Mattermost 帖子 id。</li><li><code>emoji</code> 接受名称如 <code>thumbsup</code> 或 <code>:+1:</code>（冒号可选）。</li><li>设置 <code>remove=true</code>（布尔值）移除反应。</li><li>反应添加/移除事件作为系统事件转发到路由的代理会话。</li></ul><p>示例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>message action=react channel=mattermost target=channel:&lt;channelId&gt; messageId=&lt;postId&gt; emoji=thumbsup</span></span>\n<span class="line"><span>message action=react channel=mattermost target=channel:&lt;channelId&gt; messageId=&lt;postId&gt; emoji=thumbsup remove=true</span></span></code></pre></div><p>配置：</p><ul><li><code>channels.mattermost.actions.reactions</code>：启用/禁用反应操作（默认 true）。</li><li>按账户覆盖：<code>channels.mattermost.accounts.&lt;id&gt;.actions.reactions</code>。</li></ul><h2 id="交互式按钮-消息工具" tabindex="-1">交互式按钮（消息工具） <a class="header-anchor" href="#交互式按钮-消息工具" aria-label="Permalink to &quot;交互式按钮（消息工具）&quot;">​</a></h2><p>发送带有可点击按钮的消息。当用户点击按钮时，代理接收选择并可以回复。</p><p>通过将 <code>inlineButtons</code> 添加到渠道功能来启用按钮：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    mattermost</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      capabilities</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;inlineButtons&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>使用带有 <code>buttons</code> 参数的 <code>message action=send</code>。按钮是 2D 数组（按钮行）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>message action=send channel=mattermost target=channel:&lt;channelId&gt; buttons=[[{&quot;text&quot;:&quot;Yes&quot;,&quot;callback_data&quot;:&quot;yes&quot;},{&quot;text&quot;:&quot;No&quot;,&quot;callback_data&quot;:&quot;no&quot;}]]</span></span></code></pre></div><p>按钮字段：</p><ul><li><code>text</code>（必需）：显示标签。</li><li><code>callback_data</code>（必需）：点击时发送回的值（用作操作 ID）。</li><li><code>style</code>（可选）：<code>&quot;default&quot;</code>、<code>&quot;primary&quot;</code> 或 <code>&quot;danger&quot;</code>。</li></ul><p>当用户点击按钮时：</p><ol><li>所有按钮被替换为确认行（例如&quot;✓ <strong>Yes</strong> selected by @user&quot;）。</li><li>代理将选择作为入站消息接收并回复。</li></ol><p>注意：</p><ul><li>按钮回调使用 HMAC-SHA256 验证（自动，无需配置）。</li><li>Mattermost 从其 API 响应中剥离回调数据（安全功能），因此点击时所有按钮都被移除——无法部分移除。</li><li>包含连字符或下划线的操作 ID 会自动清理（Mattemost 路由限制）。</li></ul><p>配置：</p><ul><li><code>channels.mattermost.capabilities</code>：功能字符串数组。添加 <code>&quot;inlineButtons&quot;</code> 以在代理系统提示中启用按钮工具描述。</li><li><code>channels.mattermost.interactions.callbackBaseUrl</code>：按钮回调的可选外部基础 URL（例如 <code>https://gateway.example.com</code>）。当 Mattermost 无法直接在其绑定主机上到达网关时使用此选项。</li><li>在多账户设置中，您也可以在同一字段下设置 <code>channels.mattermost.accounts.&lt;id&gt;.interactions.callbackBaseUrl</code>。</li><li>如果省略 <code>interactions.callbackBaseUrl</code>，OpenClaw 从 <code>gateway.customBindHost</code> + <code>gateway.port</code> 派生回调 URL，然后回退到 <code>http://localhost:&lt;port&gt;</code>。</li><li>可达性规则：按钮回调 URL 必须可从 Mattermost 服务器到达。<code>localhost</code> 仅在 Mattermost 和 OpenClaw 运行在同一主机/网络命名空间时有效。</li><li>如果您的回调目标是私有/tailnet/内部，请将其主机/域名添加到 Mattermost <code>ServiceSettings.AllowedUntrustedInternalConnections</code>。</li></ul><h3 id="直接-api-集成-外部脚本" tabindex="-1">直接 API 集成（外部脚本） <a class="header-anchor" href="#直接-api-集成-外部脚本" aria-label="Permalink to &quot;直接 API 集成（外部脚本）&quot;">​</a></h3><p>外部脚本和 webhook 可以通过 Mattermost REST API 直接发送按钮，而不是通过代理的 <code>message</code> 工具。尽可能使用扩展中的 <code>buildButtonAttachments()</code>；如果发布原始 JSON，请遵循以下规则：</p><p><strong>有效载荷结构：</strong></p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channel_id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;channelId&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  message</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Choose an option:&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  props</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    attachments</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        actions</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mybutton01&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 仅字母数字 - 见下文</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;button&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 必需，否则点击被静默忽略</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Approve&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 显示标签</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            style</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;primary&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 可选：&quot;default&quot;、&quot;primary&quot;、&quot;danger&quot;</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            integration</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">              url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://gateway.example.com/mattermost/interactions/default&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">              context</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">                action_id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mybutton01&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 必须匹配按钮 id（用于名称查找）</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">                action</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;approve&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                // ... 任何自定义字段 ...</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">                _token</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;hmac&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 见下文 HMAC 部分</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">              },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        ],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>关键规则：</strong></p><ol><li>附件放在 <code>props.attachments</code> 中，而不是顶层 <code>attachments</code>（静默忽略）。</li><li>每个操作需要 <code>type: &quot;button&quot;</code> —— 没有它，点击被静默吞下。</li><li>每个操作需要 <code>id</code> 字段 —— Mattermost 忽略没有 ID 的操作。</li><li>操作 <code>id</code> 必须是<strong>仅字母数字</strong>（<code>[a-zA-Z0-9]</code>）。连字符和下划线会破坏 Mattermost 的服务器端操作路由（返回 404）。使用前剥离它们。</li><li><code>context.action_id</code> 必须匹配按钮的 <code>id</code>，以便确认消息显示按钮名称（例如&quot;Approve&quot;）而不是原始 ID。</li><li><code>context.action_id</code> 是必需的 —— 没有它，交互处理程序返回 400。</li></ol><p><strong>HMAC 令牌生成：</strong></p><p>网关使用 HMAC-SHA256 验证按钮点击。外部脚本必须生成与网关验证逻辑匹配的令牌：</p><ol><li>从机器人令牌派生密钥： <code>HMAC-SHA256(key=&quot;openclaw-mattermost-interactions&quot;, data=botToken)</code></li><li>构建包含所有字段（<strong>除</strong> <code>_token</code> 之外）的上下文对象。</li><li>使用<strong>排序键</strong>和<strong>无空格</strong>序列化（网关使用 <code>JSON.stringify</code> 和排序键，产生紧凑输出）。</li><li>签名：<code>HMAC-SHA256(key=secret, data=serializedContext)</code></li><li>将生成的十六进制摘要作为 <code>_token</code> 添加到上下文中。</li></ol><p>Python 示例：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> hmac, hashlib, json</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">secret </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> hmac.new(</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;openclaw-mattermost-interactions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bot_token.encode(), hashlib.sha256</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).hexdigest()</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ctx </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;action_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mybutton01&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;action&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;approve&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">payload </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> json.dumps(ctx, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">sort_keys</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">True</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">separators</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;,&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;:&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">token </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> hmac.new(secret.encode(), payload.encode(), hashlib.sha256).hexdigest()</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">context </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ctx, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: token}</span></span></code></pre></div><p>常见 HMAC 陷阱：</p><ul><li>Python 的 <code>json.dumps</code> 默认添加空格（<code>{&quot;key&quot;: &quot;val&quot;}</code>）。使用 <code>separators=(&quot;,&quot;, &quot;:&quot;)</code> 来匹配 JavaScript 的紧凑输出（<code>{&quot;key&quot;:&quot;val&quot;}</code>）。</li><li>始终签署<strong>所有</strong>上下文字段（减去 <code>_token</code>）。网关剥离 <code>_token</code> 然后签署剩余内容。签署子集会导致静默验证失败。</li><li>使用 <code>sort_keys=True</code> —— 网关在签名之前对键进行排序，存储有效载荷时 Mattermost 可能会重新排序上下文字段。</li><li>从机器人令牌派生密钥（确定性的），而不是随机字节。创建按钮和验证的网关必须使用相同的密钥。</li></ul><h2 id="目录适配器" tabindex="-1">目录适配器 <a class="header-anchor" href="#目录适配器" aria-label="Permalink to &quot;目录适配器&quot;">​</a></h2><p>Mattermost 插件包含一个目录适配器，通过 Mattermost API 解析频道和用户名。这使得 <code>openclaw message send</code> 和 cron/webhook 投递中的 <code>#channel-name</code> 和 <code>@username</code> 目标成为可能。</p><p>无需配置 —— 适配器使用账户配置中的机器人令牌。</p><h2 id="多账户" tabindex="-1">多账户 <a class="header-anchor" href="#多账户" aria-label="Permalink to &quot;多账户&quot;">​</a></h2><p>Mattermost 支持在 <code>channels.mattermost.accounts</code> 下使用多个账户：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    mattermost</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      accounts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        default</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Primary&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">botToken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mm-token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">baseUrl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://chat.example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        alerts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Alerts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">botToken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mm-token-2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">baseUrl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://alerts.example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="故障排除" tabindex="-1">故障排除 <a class="header-anchor" href="#故障排除" aria-label="Permalink to &quot;故障排除&quot;">​</a></h2><ul><li>频道中无回复：确保机器人在频道中并提及它（oncall），使用触发前缀（onchar），或设置 <code>chatmode: &quot;onmessage&quot;</code>。</li><li>认证错误：检查机器人令牌、基础 URL，以及账户是否启用。</li><li>多账户问题：环境变量仅适用于 <code>default</code> 账户。</li><li>按钮显示为白色框：代理可能发送了格式错误的按钮数据。检查每个按钮是否都有 <code>text</code> 和 <code>callback_data</code> 字段。</li><li>按钮渲染但点击无效：验证 Mattermost 服务器配置中的 <code>AllowedUntrustedInternalConnections</code> 包含 <code>127.0.0.1 localhost</code>，并且 <code>ServiceSettings</code> 中 <code>EnablePostActionIntegration</code> 为 <code>true</code>。</li><li>点击返回 404：按钮 <code>id</code> 可能包含连字符或下划线。Mattemost 的操作路由在非字母数字 ID 上中断。仅使用 <code>[a-zA-Z0-9]</code>。</li><li>网关日志 <code>invalid _token</code>：HMAC 不匹配。检查您是否签署了所有上下文字段（不是子集），使用排序键，并使用紧凑 JSON（无空格）。见上文 HMAC 部分。</li><li>网关日志 <code>missing _token in context</code>：<code>_token</code> 字段不在按钮的上下文中。确保在构建集成有效载荷时包含它。</li><li>确认显示原始 ID 而不是按钮名称：<code>context.action_id</code> 与按钮的 <code>id</code> 不匹配。将两者设置为相同的清理值。</li><li>代理不知道按钮：在 Mattermost 渠道配置中添加 <code>capabilities: [&quot;inlineButtons&quot;]</code>。</li></ul>',96)])])}]]);export{n as __pageData,l as default};
